1	'use client'
2	
3	import { useCallback, useRef } from 'react'
4	import { AgGridReact } from 'ag-grid-react'
5	import type { ColDef, GridReadyEvent, RowClickedEvent, SelectionChangedEvent } from 'ag-grid-community'
6	
7	import 'ag-grid-community/styles/ag-grid.css'
8	import 'ag-grid-community/styles/ag-theme-alpine.css'
9	
10	interface DataTableProps<T> {
11	    columnDefs: ColDef<T>[]
12	    rowData: T[]
13	    onRowClick?: (row: T) => void
14	    onSelectionChange?: (rows: T[]) => void
15	    loading?: boolean
16	    height?: number
17	}
18	
19	export function DataTable<T>({
20	    columnDefs,
21	    rowData,
22	    onRowClick,
23	    onSelectionChange,
24	    loading = false,
25	    height = 500,
26	}: DataTableProps<T>) {
27	    const gridRef = useRef<AgGridReact<T>>(null)
28	
29	    const defaultColDef: ColDef = {
30	        sortable: true,
31	        resizable: true,
32	    }
33	
34	    const onRowClickedHandler = useCallback(
35	        (event: RowClickedEvent<T>) => {
36	            if (onRowClick && event.data) {
37	                onRowClick(event.data)
38	            }
39	        },
40	        [onRowClick]
41	    )
42	
43	    const onSelectionChangedHandler = useCallback(
44	        (event: SelectionChangedEvent<T>) => {
45	            if (onSelectionChange) {
46	                const selected = event.api.getSelectedRows()
47	                onSelectionChange(selected)
48	            }
49	        },
50	        [onSelectionChange]
51	    )
52	
53	    const onGridReady = useCallback((_event: GridReadyEvent) => {
54	        // grid ready
55	    }, [])
56	
57	    return (
58	        <div className="ag-theme-alpine" style={{ height, width: '100%' }}>
59	            <AgGridReact<T>
60	                ref={gridRef}
61	                columnDefs={columnDefs}
62	                rowData={rowData}
63	                defaultColDef={defaultColDef}
64	                rowSelection="single"
65	                pagination={true}
66	                paginationPageSize={20}
67	                loading={loading}
68	                overlayNoRowsTemplate="<span>데이터가 없습니다</span>"
69	                onRowClicked={onRowClickedHandler}
70	                onSelectionChanged={onSelectionChangedHandler}
71	                onGridReady={onGridReady}
72	            />
73	        </div>
74	    )
75	}
76
